// Pull every ensures-conjunct into the proof context for *both* runs,
// so that the corresponding quantifier triggers fire and z3 can line
// up the two ensures clauses.

// --- wf() and dom() facts for both runs ---
assert(post1_self_.wf());
assert(post2_self_.wf());

assert(post1_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr));
assert(post2_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr));
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());

assert(post1_self_.proc_dom() == pre_self_.proc_dom());
assert(post2_self_.proc_dom() == pre_self_.proc_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());

assert(post1_self_.container_dom() == pre_self_.container_dom());
assert(post2_self_.container_dom() == pre_self_.container_dom());
assert(post1_self_.container_dom() =~= post2_self_.container_dom());

// --- threads_unchanged_except with set![] forces every surviving
//     thread to equal its pre-state image, on both runs ---
let empty_threads: Set<ThreadPtr> = Set::empty();
assert(threads_unchanged_except(pre_self_, post1_self_, set![]));
assert(threads_unchanged_except(pre_self_, post2_self_, set![]));
assert forall|t_ptr: ThreadPtr|
    post1_self_.thread_dom().contains(t_ptr)
    implies #[trigger] post1_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr) by {
    assert(post2_self_.thread_dom().contains(t_ptr));
    assert(!empty_threads.contains(t_ptr));
    assert(post1_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
    assert(post2_self_.get_thread(t_ptr) =~= pre_self_.get_thread(t_ptr));
}

// --- process_tree_unchanged + process_mem_unchanged + owned_threads
//     update pin every surviving process to its pre-state image on
//     both runs ---
assert(process_tree_unchanged(pre_self_, post1_self_));
assert(process_tree_unchanged(pre_self_, post2_self_));
assert(process_mem_unchanged(pre_self_, post1_self_));
assert(process_mem_unchanged(pre_self_, post2_self_));

let owning_proc = pre_self_.get_thread(thread_ptr).owning_proc;
assert(post1_self_.get_proc(owning_proc).owned_threads@
    == pre_self_.get_proc(owning_proc).owned_threads@.remove_value(thread_ptr));
assert(post2_self_.get_proc(owning_proc).owned_threads@
    == pre_self_.get_proc(owning_proc).owned_threads@.remove_value(thread_ptr));
assert(post1_self_.get_proc(owning_proc).owned_threads.len()
    == pre_self_.get_proc(owning_proc).owned_threads.len() - 1);
assert(post2_self_.get_proc(owning_proc).owned_threads.len()
    == pre_self_.get_proc(owning_proc).owned_threads.len() - 1);

// --- containers_tree_unchanged pins every container too ---
assert(containers_tree_unchanged(pre_self_, post1_self_));
assert(containers_tree_unchanged(pre_self_, post2_self_));

// --- page_closure / return value facts ---
assert(post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0));
assert(post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0));
assert(pre_self_.page_closure().contains(r1.0));
assert(pre_self_.page_closure().contains(r2.0));
assert(r1.0 == r1.1@.addr());
assert(r2.0 == r2.1@.addr());
assert(r1.1@.is_init());
assert(r2.1@.is_init());
assert(pre_self_.container_dom().contains(r1.0) == false);
assert(pre_self_.container_dom().contains(r2.0) == false);

// --- Set extensionality on page_closure: both runs see the same
//     post-state page_closure once we know post1 == post2 on the
//     non-page-closure fields. Tie r1.0 and r2.0 via the closure. ---
assert(pre_self_.page_closure().remove(r1.0) =~= post1_self_.page_closure());
assert(pre_self_.page_closure().remove(r2.0) =~= post2_self_.page_closure());
